const fs = require('fs');
const path = require('path');
const ENV_FILE = path.join(process.env.HOME||'/root', 'autotrader', 'n8n_autotrader.env');
const STATE_FILE = path.join(process.env.HOME||'/root', 'autotrader', 'active_trades.json');
const today = new Date().toISOString().split('T')[0];

// Load env for Twilio credentials
const env = {};
try {
  const raw = fs.readFileSync(ENV_FILE, 'utf8');
  for (const line of raw.split('\n')) {
    const t = line.trim();
    if (!t || t.startsWith('#')) continue;
    const i = t.indexOf('=');
    if (i < 0) continue;
    env[t.slice(0,i).trim()] = t.slice(i+1).trim();
  }
} catch(e) { console.log('No .env file found'); }

let state = null;
try {
  state = JSON.parse(fs.readFileSync(STATE_FILE, 'utf8'));
} catch(e) {
  state = { date: today, trades: [], noTradesDay: true };
}

return [{ json: {
  ...state,
  TWILIO_ACCOUNT_SID:   state.TWILIO_ACCOUNT_SID   || env.TWILIO_ACCOUNT_SID   || '',
  TWILIO_AUTH_TOKEN:    state.TWILIO_AUTH_TOKEN     || env.TWILIO_AUTH_TOKEN     || '',
  TWILIO_WHATSAPP_FROM: state.TWILIO_WHATSAPP_FROM  || env.TWILIO_WHATSAPP_FROM  || '',
  ALERT_PHONE:          state.ALERT_PHONE           || env.ALERT_PHONE           || '',
  today, stateFile: STATE_FILE
}}];

// Identify any still-open MIS positions to force exit
const data = items[0].json;
const openTrades = (data.trades||[]).filter(t => t.status === 'OPEN');
// Return one item per open trade for the SELL HTTP node
if (openTrades.length === 0) {
  return [{ json: { ...data, forceExits: [], hasForceExits: false } }];
}
return [{ json: { ...data, forceExits: openTrades, hasForceExits: true } }];

const data = items[0].json;
const trades = data.trades||[];
const today = data.today||new Date().toISOString().split('T')[0];
const dateDisplay = new Date(today).toLocaleDateString('en-IN',{day:'2-digit',month:'short',year:'numeric'});

if (data.noTradesDay || trades.length === 0) {
  return [{ json: { ...data, eodMessage:
    `📋 *DAILY SUMMARY — ${dateDisplay}*\n\n` +
    `No trades were placed today.\nMarket conditions were unfavourable.\n\n` +
    `⚙️ Auto-Trader by n8n + Zerodha`
  }}];
}

const closed = trades.filter(t=>t.status==='CLOSED'||t.status==='CLOSING');
const open   = trades.filter(t=>t.status==='OPEN');

const totalPnL    = trades.reduce((s,t)=>s+(t.pnl||0),0);
const totalCost   = trades.reduce((s,t)=>s+(t.costToTrade||0),0);
const winners     = closed.filter(t=>(t.pnl||0)>0).length;
const losers      = closed.filter(t=>(t.pnl||0)<=0).length;

const emoji = r => r==='TARGET_HIT'?'🎯':r==='STOPLOSS_HIT'?'🛑':'⏰';
const tradeLines = trades.map(t=>{
  const p=t.pnl||0,pp=t.pnlPct||0;
  return `${emoji(t.exitReason||'EOD_SQUAREOFF')} ${t.symbol}: Entry ₹${t.entryPrice} → Exit ₹${t.ltp||'N/A'} | ${p>=0?'+':''}₹${p.toFixed(0)}(${pp>=0?'+':''}${pp.toFixed(1)}%)`;
}).join('\n');

const overallEmoji = totalPnL>0?'🟢':totalPnL<0?'🔴':'⚪';
const msg=
  `📋 *DAILY SUMMARY — ${dateDisplay}*\n` +
  `━━━━━━━━━━━━━━━━━━\n` +
  `${tradeLines}\n` +
  `━━━━━━━━━━━━━━━━━━\n` +
  `${overallEmoji} Net P&L: ${totalPnL>=0?'+':''}₹${totalPnL.toFixed(2)}\n` +
  `📦 Invested: ₹${totalCost.toFixed(2)}\n` +
  `✅ Winners: ${winners} | ❌ Losers: ${losers}\n` +
  `📊 Total trades: ${trades.length}\n\n` +
  `⚙️ Auto-Trader by n8n + Zerodha\n` +
  `Next session: Tomorrow 9:45 AM`;

return[{json:{...data,eodMessage:msg,totalPnL:+totalPnL.toFixed(2),winners,losers}}];
